datasets.sort()

# Fit a simple logistic to a few datasets and check residuals
# to understand what structure is missing
from scipy.optimize import least_squares

def richards_logt(x0, x1, c):
    log_t = np.log(c[7] * x0 + 1)
    rate = c[0] + c[1] * np.log(x1)
    half = c[2] + c[3] * np.log(x1)
    return c[5] / (1 + np.exp(-rate * (log_t - half)))**c[4] + c[6]

# Test on a few datasets
test_datasets = [
    'lysozyme/Fits/Hasecke2018_70uM_sec/fit.tsv',
    'htt/Kar2011/Fits/Kar2011_Q30_without_lowest_conc_sec/fit.tsv',
    'serum amyloid/Ye2011/Fits/Ye2011_sec/fit.tsv',
    'Abeta/Cohen2013/Ab42_sec_IN_HOURS/fit.tsv',
]

for tname in test_datasets:
    path = os.path.join(base, tname)
    with open(path) as f:
        reader = csv.reader(f, delimiter='\t')
        header = next(reader)
        rows = [r for r in reader if r]

    import re
    params = []
    for h in header[1:]:
        m = re.search(r'(\d+(?:\.\d+)?)\s*uM', h, re.IGNORECASE)
        if m:
            params.append(float(m.group(1)))
        else:
            m = re.search(r'(\d+(?:\.\d+)?)\s*mg/mL', h, re.IGNORECASE)
            if m:
                params.append(float(m.group(1)))
            else:
                params.append(float(len(params)+1))

    X, y = [], []
    for row in rows:
        for i, (p, v) in enumerate(zip(params, row[1:])):
            if v.strip() and v.strip().lower() != 'nan':
                X.append([float(row[0]), p])
                y.append(float(v))
    X, y = np.array(X), np.array(y)

    def resid(c):
        try:
            pred = richards_logt(X[:,0], X[:,1], c)
            if not np.all(np.isfinite(pred)):
                return np.full(len(y), 1e6)
            return pred - y
        except:
            return np.full(len(y), 1e6)

    c0 = [1.0, 0.0, 2.0, 0.0, 1.0, 1.0, 0.0, 0.001]
    res = least_squares(resid, c0, loss='soft_l1', max_nfev=300)
    pred = richards_logt(X[:,0], X[:,1], res.x)
    nmse = np.mean((pred - y)**2) / np.var(y) if np.var(y) > 0 else float('inf')
    print(f'{tname}: nmse={nmse:.4f}, c={[f\"{v:.3f}\" for v in res.x]}')
